sql:
SELECT institution_id, rating
FROM institution_ratings
WHERE rating_year = 2023;

SELECT AVG(capacity) AS average_capacity, MAX(capacity) AS max_capacity
FROM institution_facilities
WHERE institution_id = 1;

SELECT COUNT(staff_id) AS number_of_staff
FROM institution_staff
WHERE institution_id = 1;

SELECT staff_name
FROM institution_staff
WHERE designation = 'professor' AND department = 'Mathematics';

SELECT institution_name
FROM institutions
ORDER BY institution_name;

SELECT institution_name
FROM institutions
ORDER BY institution_name;

SELECT institution_name
FROM institutions
ORDER BY institution_name;

